const msg = $input.first().json;

const chatId = msg?.message?.chat?.id || msg?.callback_query?.message?.chat?.id;
const userId = String(msg?.message?.from?.id || msg?.callback_query?.from?.id || '');
const firstName = msg?.message?.from?.first_name || 'there';
const text = (msg?.message?.text || '').trim();

const isStart = text === '/start';
const isHelp = text === '/help';
const isReset = text === '/reset';
const isCommand = isStart || isHelp || isReset;
const isEmpty = !text;

return [{
  json: { chatId, userId, firstName, text, isStart, isHelp, isReset, isCommand, isEmpty }
}];

const embeddingResponse = $input.first().json;
const userText = $('Parse Message2').item.json.text;
const userId = $('Parse Message2').item.json.userId;
const chatId = $('Parse Message2').item.json.chatId;

const vector = embeddingResponse?.data?.[0]?.embedding
  || embeddingResponse?.embedding
  || [];

if (!vector.length) {
  throw new Error('Failed to get embedding from OpenAI');
}

// Store as array, not string - let the SQL node handle formatting
return [{ json: { 
  userText, 
  userId, 
  chatId, 
  queryVector: vector,  // Keep as array
  queryVectorStr: '[' + vector.join(',') + ']'  // Pre-built string version
}}];

const item = $input.first().json;
const userText = item.userText;
const userId   = item.userId;
const chatId   = item.chatId;
const kbChunks = item.kbChunks || [];
const history  = item.history  || [];

const contextText = kbChunks.length > 0
  ? kbChunks.map(c => '[Source: ' + c.file_name + ']\n' + c.content).join('\n\n---\n\n')
  : '';

const systemPrompt = `You are the Auki Knowledge Agent - an official representative of Auki.com.
You help investors, developers, and curious people learn everything about Auki and the posemesh.

IDENTITY RULES:
- You ARE part of the Auki team. Use "we", "our", "us" when referring to Auki.
- Speak with authority and warmth as someone who works at Auki.

ANTI-REPETITION RULES:
- Read the full conversation history above before replying.
- If you already answered this question or covered this topic, DO NOT repeat it. Say: "As mentioned above, ..." and add only new detail.
- NEVER re-introduce Auki or the Posemesh if already done in this conversation.
- NEVER open your reply with a greeting like "Hi there!", "Hello!", "Hey!", or any variant. Go straight to answering the question.
- If the user asks the same question twice, acknowledge it briefly and add new information.

TONE RULES:
- Technical questions: be nerdy, precise, deep. Cover spatial computing, decentralization, SLAM, AR anchoring, multi-agent robotics.
- Investor questions: professional, factual, investor-relations style. No hype, no price speculation.
- Always concise. Respect the reader's time.

FORMATTING:
- More than 4 sentences: split into short paragraphs.
- NEVER exceed 8000 characters.
- NEVER use em dashes or en dashes. Use hyphens (-) only.
- Always write "Posemesh" with a capital P. Never write "posemesh".
- Bullet points are fine for lists.

CONTENT RULES:
- Answer questions about the Auki team, founders, and advisors using the knowledge base context. If team info is in the context, always answer specifically.
- Only answer from official Auki sources and the knowledge base context provided.
- If a topic is genuinely not in official sources, reply: "I don't have any official information on that."
- No financial projections or token price predictions.`;

const knowledgeContext = contextText
  ? 'RELEVANT KNOWLEDGE BASE CONTEXT (from official Auki documents):\n\n' + contextText
  : 'No matching knowledge base content found. Use general Auki knowledge or say you do not have official information.';

const messages = [
  { role: 'system', content: systemPrompt },
  { role: 'system', content: knowledgeContext },
  ...history,
  { role: 'user', content: userText }
].filter(m => m && typeof m.role === 'string' && typeof m.content === 'string' && m.content.trim() !== '');

const openAiBody = JSON.stringify({
  model: 'gpt-4o',
  messages: messages,
  temperature: 0.3,
  max_tokens: 1000
});

return [{ json: { messages, openAiBody, userText, userId, chatId } }];

const raw      = $input.first().json;
const bp       = $('Build Prompt2').first().json;
const parsed   = $('Parse Message2').first().json;

const userText = bp.userText || parsed.text  || '';
const userId   = bp.userId   || parsed.userId || '';
const chatId   = bp.chatId   || parsed.chatId || '';

let reply = raw?.choices?.[0]?.message?.content
  || raw?.content
  || raw?.text
  || raw?.message?.content
  || 'Sorry, I ran into an issue generating a response. Please try again.';

if (reply.length > 4096) {
  reply = reply.substring(0, 4090) + '...';
}

const userTextSafe = userText.replace(/'/g, "''");
const replySafe    = reply.replace(/'/g, "''");

return [{ json: { reply, userText, userId, chatId, userTextSafe, replySafe } }];

// Pull text directly from the named Extract Text node
const rawText = $('Extract Text2').item.json.text;

if (!rawText || rawText.length < 50) {
  throw new Error('No text extracted. Length: ' + (rawText || '').length);
}

// Dynamically get file info from the Google Drive Trigger output
const triggerData = $('Google Drive Trigger2').item.json;
const fileId = triggerData.id || triggerData.fileId || 'YOUR_GOOGLE_DRIVE_FILE_ID';
const fileName = triggerData.name || triggerData.fileName || 'Auki Knowledge Base';
const CHUNK_SIZE = 800;
const OVERLAP = 150;

const paragraphs = rawText.split(/\n\n+/).filter(p => p.trim().length > 20);
const chunks = [];
let current = '';
let idx = 0;

for (const para of paragraphs) {
  const t = para.trim();
  if ((current + '\n\n' + t).length <= CHUNK_SIZE) {
    current = current ? current + '\n\n' + t : t;
  } else {
    if (current.length > 50) {
      chunks.push({ fileId, fileName, chunkIndex: idx, content: current.trim() });
      idx++;
    }
    current = current.slice(-OVERLAP) + '\n\n' + t;
  }
}
if (current.trim().length > 50) {
  chunks.push({ fileId, fileName, chunkIndex: idx, content: current.trim() });
}

console.log('Total chunks:', chunks.length, '| File:', fileName, '| ID:', fileId);
return chunks.map(c => ({ json: c }));

const allChunks = $input.all().map(i => i.json);
return [{ json: {
  fileId: allChunks[0].fileId,
  fileName: allChunks[0].fileName,
  totalChunks: allChunks.length,
  chunks: allChunks
}}];

const chunk = $('Re-emit Chunks2').item.json;
const embeddingResponse = $input.item.json;
const embeddingVector = embeddingResponse?.data?.[0]?.embedding || [];

if (!embeddingVector.length) {
  throw new Error('No embedding for chunk ' + chunk.chunkIndex);
}

// Pre-escape single quotes for safe SQL interpolation
const escapeSql = s => String(s).replace(/'/g, "''");

return {
  json: {
    file_id:     escapeSql(chunk.fileId),
    file_name:   escapeSql(chunk.fileName),
    chunk_index: chunk.chunkIndex,
    content:     escapeSql(chunk.content),
    embedding:   '[' + embeddingVector.join(',') + ']',
    metadata:    escapeSql(JSON.stringify(chunk.metadata || {}))
  }
};

return items.map(item => ({ json: {
  status: 'success',
  message: 'Inserted chunk #' + item.json.chunk_index + ' of ' + item.json.file_name,
  timestamp: new Date().toISOString()
}}));

const data = $input.first().json;
const vector = data.queryVector;
const vectorStr = vector.join(',');

// Pre-build raw JSON body for Supabase RPC call — avoids bodyParameters
// type-coercion issues with number fields and array values.
const supabaseBody = JSON.stringify({
  query_embedding: vector,
  match_threshold: 0.0,
  match_count: 5
});

return [{ json: {
  userText: data.userText,
  userId: data.userId,
  chatId: data.chatId,
  queryVector: vector,
  queryVectorStr: vectorStr,
  supabaseBody: supabaseBody
}}];

// HTTP Request returns 0-5 rows from Supabase vector search.
// Collect ALL of them into one item so the next node runs exactly once.
const allItems = $input.all();
const kbChunks = allItems
  .filter(i => i.json && i.json.content)
  .map(i => ({ content: i.json.content, file_name: i.json.file_name || 'Auki KB' }));

// Preserve routing context from upstream
const ctx = $('Code in JavaScript2').first().json;

return [{ json: {
  userText:      ctx.userText,
  userId:        ctx.userId,
  chatId:        ctx.chatId,
  kbChunks:      kbChunks
}}];

const inputItems = $input.all();

// History rows come from Fetch Conversation History2 via $input
const historyItems = inputItems.filter(i => i.json.role && i.json.content);

// Context (kbChunks, userText, userId, chatId) pulled directly from upstream node
// This avoids depending on Aggregate KB Results1 as a second input
const ctx = $('Aggregate KB Results1').first().json;

const history = historyItems
  .map(i => ({ role: i.json.role, content: i.json.content }));

return [{ json: {
  userText: ctx.userText,
  userId:   ctx.userId,
  chatId:   ctx.chatId,
  kbChunks: ctx.kbChunks || [],
  history:  history
}}];
